<?php
function register_user() {
    if (isset($_POST['username']) && isset($_POST['email']) && isset($_POST['password'])) {
        $username = sanitize_text_field($_POST['username']);
        $email = sanitize_email($_POST['email']);
        $password = $_POST['password'];

        if (!username_exists($username) && !email_exists($email)) {
            $user_id = wp_create_user($username, $password, $email);
            update_user_meta($user_id, 'first_name', $username);

            return array('success' => true, 'message' => 'User created successfully');
        } else {
            return array('success' => false, 'message' => 'Username or email already exists');
        }
    }

    return array('success' => false, 'message' => 'Invalid request');
}

function login_user() {
    if (isset($_POST['username']) && isset($_POST['password'])) {
        $username = sanitize_text_field($_POST['username']);
        $password = $_POST['password'];

        $user = get_user_by('login', $username);
        if ($user) {
            $hashed_password = get_user_meta($user->ID, 'user_pass', true);

            if (wp_check_password($password, $hashed_password, $user->ID)) {
                return array('success' => true, 'message' => 'Logged in successfully');
            } else {
                return array('success' => false, 'message' => 'Invalid password');
            }
        } else {
            return array('success' => false, 'message' => 'Invalid username or email');
        }
    }

    return array('success' => false, 'message' => 'Invalid request');
}

function register_hooks() {
    add_action('wp_ajax_nopriv_register_user', 'register_user');
    add_action('wp_ajax_register_user', 'register_user');

    add_action('wp_ajax_nopriv_login_user', 'login_user');
    add_action('wp_ajax_login_user', 'login_user');
}

add_action('init', 'register_hooks');